23	-- $$ PROCESSES=Input,Output $$
24	
25	------------------------------------------------------------------------------
26	-- Entity Declaration
27	------------------------------------------------------------------------------
28	entity psi_common_async_fifo is
29		generic (
30			Width_g			: positive		:= 16;	-- $$ EXPORT=true $$
31			Depth_g			: positive		:= 32;	-- $$ EXPORT=true; funky=bla $$
32			AlmFullOn_g		: boolean		:= false;-- $$ EXPORT=false,funky=blubb $$
33			AlmFullLevel_g	: natural		:= 28; --$$CONSTANT=12$$
34			AlmEmptyOn_g	: boolean		:= false;
35			AlmEmptyLevel_g	: natural		:= 4
36		);
37		port (
38			-- Control Ports
39			InClk		: in	std_logic;	-- $$ TYPE=CLK; FREQ=100e6; PROC=Input $$
40			InRst		: in	std_logic;	-- $$ TYPE=RST; CLK=InClk $$
41			OutClk		: in 	std_logic;	-- $$ TYPE=CLK; FREQ=125e6; Proc=Output $$
42			OutRst		: in 	std_logic;	-- $$ TYPE=RST; CLK=OutClk $$
43	
44			-- Input Data
45			InData		: in	std_logic_vector(Width_g-1 downto 0) := (others => '0');	-- $$ PROC=Input$$
46			InVld		: in	std_logic;													-- $$ PROC=INPUT$$
47			InRdy		: out	std_logic;	-- not full	$$PROC=input$$
48	
49			-- Output Data
50			OutData		: out	std_logic_vector(Width_g-1 downto 0);	-- $$ PROC=Output$$
51			OutVld		: out	std_logic;	-- not empty				-- $$ PROC=Output$$
52			OutRdy		: in	std_logic := '1';						-- $$ PROC=Output,Input$$
53	
54			-- Input Status
55			InFull		: out	std_logic;
56			InEmpty		: out	std_logic;
57			InAlmFull 	: out	std_logic;
58			InAlmEmpty	: out	std_logic;
59			InLevel		: out	std_logic_vector(log2ceil(Depth_g) downto 0);
60	
61			-- Output Status
62			OutFull		: out	std_logic; -- $$ PROC=Input,Output $$
63			OutEmpty	: out	std_logic;
64			OutAlmFull	: out	std_logic;
65			OutAlmEmpty : out 	std_logic;
66			OutLevel	: out	std_logic_vector(log2ceil(Depth_g) downto 0)
67		);
68	end entity;
